import 'dart:typed_data';
import 'package:oraculo_ia/src/features/content/domain/knowledge_content.dart';
import 'package:pdf/pdf.dart';
import 'package:pdf/widgets.dart' as pw;
enum ExportScope{complete,chapter,topic,favorites,review}
class ManualExporter{const ManualExporter();String markdown(KnowledgeContent c,{ExportScope scope=ExportScope.complete,Set<String> selected=const {}}){final a=_articles(c,scope,selected);return '# ORÁCULO IA - Manual Maestro\n\nVersión 2.6 · Generado ${DateTime.now().toIso8601String().split('T').first}\n\n## Índice\n${a.map((e)=>'- [${e.title}](#${e.id})').join('\n')}\n\n${a.map((e)=>'## ${e.title}\n\n${e.body}\n\nFuentes y conceptos: ${e.links.join(', ')}').join('\n\n')}\n\n## Glosario\n${c.terms.map((e)=>'**${e.term}:** ${e.definition}').join('\n\n')}';}String html(KnowledgeContent c,{ExportScope scope=ExportScope.complete,Set<String> selected=const {}})=>'<!doctype html><html lang="es"><meta charset="utf-8"><title>Manual Maestro</title><style>body{font:18px system-ui;max-width:760px;margin:auto;padding:32px;background:#111;color:#eee}a{color:#9ecbff}h1,h2{color:#fff}</style><body>${markdown(c,scope:scope,selected:selected).split('\n').map((line)=>line.startsWith('# ')?'<h1>${line.substring(2)}</h1>':line.startsWith('## ')?'<h2 id="${line.substring(3).toLowerCase().replaceAll(' ','-')}">${line.substring(3)}</h2>':'<p>$line</p>').join()}</body></html>';Future<Uint8List> pdf(KnowledgeContent c,{ExportScope scope=ExportScope.complete,Set<String> selected=const {}})async{final doc=pw.Document(title:'ORÁCULO IA - Manual Maestro');final a=_articles(c,scope,selected);doc.addPage(pw.MultiPage(pageFormat:PdfPageFormat.a4,margin:const pw.EdgeInsets.all(42),header:(x)=>pw.Text('ORÁCULO IA · Manual Maestro',style:const pw.TextStyle(fontSize:9)),footer:(x)=>pw.Text('Página ${x.pageNumber} de ${x.pagesCount}',style:const pw.TextStyle(fontSize:9)),build:(x)=>[pw.SizedBox(height:80),pw.Text('ORÁCULO IA',style:pw.TextStyle(fontSize:32,fontWeight:pw.FontWeight.bold)),pw.Text('Manual Maestro offline'),pw.Text('Versión 2.6 · ${DateTime.now().toIso8601String().split('T').first}'),pw.NewPage(),pw.Header(text:'Índice'),...a.map((e)=>pw.Bullet(text:e.title)),...a.expand((e)=>[pw.Header(text:e.title),pw.Paragraph(text:e.body),pw.Text('Conceptos: ${e.links.join(', ')}')]),pw.Header(text:'Glosario'),...c.terms.map((e)=>pw.Paragraph(text:'${e.term}: ${e.definition}'))]));return doc.save();}List<KnowledgeArticle> _articles(KnowledgeContent c,ExportScope scope,Set<String>s)=>scope==ExportScope.complete?c.articles:c.articles.where((a)=>s.contains(a.id)||a.links.any(s.contains)).toList();}
